747→fn extract_concrete_values(
748→    model: &z3::Model,
749→    vars: &VarTable,
750→) -> HashMap<String, ConcreteValue> {
751→    let mut result = HashMap::new();
752→
753→    for (name, ast) in &vars.ints {
754→        if let Some(val) = model.eval(ast, true)
755→            && let Some(i) = val.as_i64()
756→        {
757→            result.insert(name.clone(), ConcreteValue::Int(i));
758→        }
759→    }
760→
761→    for (name, ast) in &vars.reals {
762→        if let Some(val) = model.eval(ast, true) {
763→            if let Some((num, den)) = val.as_rational() {
764→                if den != 0 {
765→                    result.insert(
766→                        name.clone(),
767→                        ConcreteValue::Float(num as f64 / den as f64),
768→                    );
769→                }
770→            } else {
771→                let s = val.to_string();
772→                if let Ok(f) = s.parse::<f64>() {
773→                    result.insert(name.clone(), ConcreteValue::Float(f));
774→                }
775→            }
776→        }
777→    }
778→
779→    for (name, ast) in &vars.bools {
780→        if let Some(val) = model.eval(ast, true)
781→            && let Some(b) = val.as_bool()
782→        {
783→            result.insert(name.clone(), ConcreteValue::Bool(b));
784→        }
785→    }
786→
787→    for (name, ast) in &vars.strings {
788→        if let Some(val) = model.eval(ast, true)
789→            && let Some(s) = val.as_string()
790→        {
791→            result.insert(name.clone(), ConcreteValue::Str(s));
792→        }
793→    }
794→
795→    result
796→}
