798→/// Check that solved `ConcreteValue` types are compatible with declared `ParamInfo` types.
799→/// Used as an `#[ensures]` postcondition on `solve_for_new_path`. Returns `true` when
800→/// the result is an error, unsat, or when all solved values match their param types.
801→/// A mismatch (e.g. `ConcreteValue::Int` for a `TypeInfo::Str` param) returns `false`.
802→fn solved_values_match_param_types(
803→    result: Result<&SolveResult, &SolverError>,
804→    param_infos: &[ParamInfo],
805→) -> bool {
806→    let solved = match result {
807→        Ok(SolveResult::Sat(map)) => map,
808→        // Errors and Unsat trivially satisfy the postcondition.
809→        _ => return true,
810→    };
811→    let param_map: HashMap<&str, &TypeInfo> = param_infos
812→        .iter()
813→        .map(|p| (p.name.as_str(), &p.typ))
814→        .collect();
815→    for (name, value) in solved {
816→        if let Some(ty) = param_map.get(name.as_str())
817→            && !concrete_value_matches_type(value, ty)
818→        {
819→            return false;
820→        }
821→        // Solved variables not in param_infos are sub-paths (e.g. "config.timeout")
822→        // or synthesized — no type to check against.
823→    }
824→    true
825→}
826→
827→/// Whether a `ConcreteValue` is compatible with a `TypeInfo`.
828→fn concrete_value_matches_type(value: &ConcreteValue, ty: &TypeInfo) -> bool {
829→    match (value, ty) {
830→        // Numeric types are interchangeable — Z3 may solve a Float param as Int
831→        // when the constraints only use integer comparisons, and vice versa.
832→        (ConcreteValue::Int(_) | ConcreteValue::Float(_), TypeInfo::Int | TypeInfo::Float) => true,
833→        (ConcreteValue::Str(_), TypeInfo::Str) => true,
834→        (ConcreteValue::Bool(_), TypeInfo::Bool) => true,
835→        // Nullable<inner> — the solved value should match the inner type
836→        (_, TypeInfo::Nullable { inner }) => concrete_value_matches_type(value, inner),
837→        // Complex value wraps a repr that Z3 solved — accept any complex match.
838→        (ConcreteValue::Complex { .. }, TypeInfo::Complex { .. }) => true,
839→        // Int is the Z3 default for types it can't represent (arrays, objects, unions,
840→        // unknown, opaque). Accept Int for any non-primitive type.
841→        (ConcreteValue::Int(_), _) => {
842→            !matches!(ty, TypeInfo::Str | TypeInfo::Bool)
843→        }
844→        _ => false,
845→    }
846→}

